INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-94737317-moex-00002', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「蔡廷蘭，澎湖人，道光十五年考完鄉試自金門返鄉，船遭颱風，在海上漂流十晝 夜，抵越南廣義府登岸。他請求越南政府資助護送，從廣義一路北上。而後，他把 海上風險寫成〈滄溟紀險〉，越南經歷寫成〈炎荒紀程〉，最後概述越南歷史，以 及聞見的民俗、風俗和文化，寫成〈越南紀略〉，三篇合成《海南雜著》。」 文中對於蔡廷蘭其人、其事與著作的稱許，不包含下列何者？', '["冒險犯難", "閱歷豐富", "談吐不凡", "著述詳贍 90110"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00003', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「『大觀音亭祀典興濟宮』位於臺南市鎮北坊文化園區，為國家三級古蹟，係全臺 獨一無二『佛道同祀』之古寺老廟。所處位置為府城北邊『尖山』，廟貌依勢而建。 拾階而上，但見佛祖、公祖（保生大帝）端坐正殿，慈眉善目、觀世濟人。而大觀 音亭與興濟宮兩廟之間保存之『官廳』，亦為全臺碩果僅存，更具體凸顯佛道同祀、 福慧雙修之祥和特色。」 根據上文，下列敘述何者正確？', '["主祀佛祖觀音的興濟宮是臺南古剎兼古蹟", "大觀音亭為府城獨一無二被道教化的寺廟", "因體現宗教共融精神而成為國家三級古蹟", "可以看到佛寺與宮廟共用官廳的獨特景象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00004', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「『使用者導向設計』的設計流程不離使用者的需求與限制，它以使用者為研究的 主體對象，並以此做為產品開發決策的參考依據，參與成員通常會包括心理學家、 人類學家，以及其他社會科學家。這種設計手法不會從產品概念或藉應用程式運作 的新科技著手，在嘗試改善人們生活與經驗的同時，也會試圖兼顧為客戶帶來利益 的機會。」 根據上文所說的「使用者導向設計」，下列選項何者正確？', '["便利性是設計時唯一參考依據", "結合使用者的經驗與設計概念", "以創意為主無需兼顧客戶利益", "排除任何程式運作及新興科技"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00005', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「可愛是一種以喚起躍動感、刺激生命為基礎，激發人們好奇心的狀態。然而，一 般而言我們認為可愛是美的鄰居、醜的反義詞。但如果仔細端詳被稱為可愛的事物， 會發現它與美是完全不同的，倒不如說有種對立的氛圍。至於醜的事物，如果換一 個角度來看，讓人覺得可愛的例子反倒不勝枚舉。這或許是因為，『美麗』時常與 不可碰觸聯想在一起，然而『可愛』卻總是引起人想碰觸、呵護的欲望，這其實與 支配的欲望有關。」 文中所謂「可愛」，敘述正確的是：', '["因生命刺激而引發，往往帶著好奇", "相較於美麗，不易激發呵護的欲望", "可愛的事物，可說是完美的同義詞", "因受制於支配的欲望，故不可碰觸"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00006', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '《灌籃高手》的作者井上雄彥曾在專訪中提及「最初出版社提醒他，相較於一軍的 棒球、足球，籃球漫畫只能算三軍，多半都碰上半途腰斬的鬼門關。」 根據上文，下列推論何者正確？', '["棒球、足球和籃球都是漫畫的熱門題材", "出版社相當看好井上雄彥的《灌籃高手》", "先前籃球漫畫的連載，作者常後繼無力", "相較於籃球，棒球、足球漫畫更受歡迎 90110"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00007', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「對我來說，那些飛行的重點並不在於加熱的微波餐，而是進入一種彷彿脫離塵世 的冥想狀態。飛行中手機不會響，網路可以不連結，『飛行時間就是浪費掉的時間』 這句話將我從焦慮和罪惡感中解放出來，脫去我所有的野心，給另一種生活騰出了 一塊空間。那是一種傻傻的幸福生活，不必盡力善用時間，怎麼開心就怎麼過。」 根據上文，作者喜歡飛行的原因是：', '["無可挑剔的機上餐點", "手機響起也不用接聽", "可暫時擺脫時間壓力", "無須為擺脫焦慮裝傻"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00008', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「豐田玉俗稱臺灣玉，產於花蓮壽豐鄉豐田村的荖腦溪上游，1960年代曾經盛極一 時，為臺灣賺進可觀的外匯。其實，豐田玉早在三千多年前，就已經『外銷』到東 南亞了。考古發現，臺灣東部豐田玉所製造的玉器（包括錛、箭頭、刀，以及飾品）， 從三千五百年前，就已流布到菲律賓巴丹群島、越南、泰國等地，並且持續到一千 年前。」 下列選項，最合乎本文意旨的是：', '["豐田玉製造的玉器品質精良曾稱霸東南亞", "史前時代臺灣原住民的祖先長期不諳水性", "考古顯示豐田玉曾為臺灣賺進可觀的外匯", "臺灣豐田玉在古代曾經渡海流傳到東南亞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00009', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「生物信用額度（biocredits）是指企業可以透過購買生物信用額度的方式，資助生 物多樣性的保護和管理。這種量化和追蹤生物多樣性保育工作及成果的機制，可將 資金引導至有效的生物多樣性保護，並直接支持由在地主導的行動，以確保原住民 與在地社區能夠充分參與並實現該機制的好處。」 下列有關生物信用額度的敘述，何者錯誤？', '["企業購買生物信用額度可以為生物多樣性盡一份力", "企業資金可移轉給在地社區跟原住民進行生態的監護", "獵人得以在生物信用額度下進入生物多樣性保護區狩獵", "購買森林護山貓（石虎）就是支持生物信用額度的理念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00010', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「元宇宙基於網際網路而生。隨著各種數位技術的成熟和商用的普及，元宇宙所要 構建的是一個囊括使用者、網路和各種終端設備的永續虛擬實境系統。這個系統與 現實世界相互聯通、平行存在，使用者可以借助虛擬身分進行娛樂、社交等活動， 並利用平臺資源來創作，將作品轉化為虛擬資產，真正的沉浸體驗一切。」 甲：「雖然元宇宙並非真實，但卻具備無窮商機，能提供人們另一種生活的體驗。」 乙：「元宇宙的發展日趨成熟，但是否有明確的規範來保障個人權益，仍有待研議。」 根據上文，下列關於甲、乙對元宇宙的評述，何者正確？', '["甲認同文中對於元宇宙前景所述", "乙反對文中對於現實環境的主張", "兩人對於元宇宙都著重在商用層面", "兩人對於元宇宙功能都沒表示看法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "9d320294df32", "answer_pdf_sha1": "fd38032defb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00011', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '在真空中有帶正、負電荷的粒子，⊕代表一單位的正電荷， 代表一單位的負電荷，這些電荷均以 相同的速率移動，箭頭代表移動方向，如圖所示。下列何者通過虛線截面的電流值最大？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
